### Creates a new SSO provider
# @name v1-create-a-sso-provider
POST {{host}}/v1/projects/{{ref}}/config/auth/sso/providers
Authorization: Bearer {{token}}
Content-Type: application/json
Accept: application/json

{
  "type": "saml",
  "metadata_url": "https://sso.acme.com/metadata.xml",
  "domains": [
    "acme.com"
  ],
  "attribute_mapping": {
    "keys": {
      "email": {
        "name": "email"
      },
      "first_name": {
        "name": "first_name"
      },
      "last_name": {
        "name": "last_name"
      }
    }
  }
}

## Responses
# 201
# Content-Type: application/json
# 401
# Description: Unauthorized
# 403
# Description: Forbidden action
# 404
# Description: SAML 2.0 support is not enabled for this project
# 429
# Description: Rate limit exceeded

### Updates a user mapping for JIT access
# @name v1-update-jit-access
PUT {{host}}/v1/projects/{{ref}}/database/jit
Authorization: Bearer {{token}}
Content-Type: application/json
Accept: application/json

{
  "user_id": "55555555-5555-4555-8555-555555555555",
  "roles": [
    {
      "role": "postgres",
      "expires_at": 1740787200,
      "allowed_networks": {
        "allowed_cidrs": [
          {
            "cidr": "203.0.113.0/24"
          }
        ]
      }
    }
  ]
}

